    {
        "path": "crysis-remastered-trainer/README.md",
        "content": "# Crysis Remastered Trainer\n\nA console-based trainer for Crysis Remastered (Windows).\n\n## Features\n- Unlimited Health\n- Unlimited Energy\n- Unlimited Ammo\n- Unlimited Suit Mode\n- Super Jump\n- Teleport to Waypoint\n\n## Prerequisites\n- Windows 10/11\n- Crysis Remastered (Steam/Epic)\n- .NET 8.0 Runtime\n\n## Build & Run\n```\ndotnet build\ncd bin/Debug/net8.0\n./crysis-remastered-trainer.exe\n```\n\n## Usage\n- Launch Crysis Remastered first.\n- Run the trainer as Administrator.\n- Use keyboard shortcuts to toggle cheats.\n\n## Disclaimer\nFor educational purposes only. Use at your own risk."
    },
    {
        "path": "crysis-remastered-trainer/crysis-remastered-trainer.csproj",
        "content": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net8.0</TargetFramework>\n    <RootNamespace>CrysisRemasteredTrainer</RootNamespace>\n    <AssemblyName>crysis-remastered-trainer</AssemblyName>\n    <PlatformTarget>x64</PlatformTarget>\n    <AllowUnsafeBlocks>true</AllowUnsafeBlocks>\n  </PropertyGroup>\n  <ItemGroup>\n    <PackageReference Include=\"Memory.dll\" Version=\"1.0.4\" />\n  </ItemGroup>\n</Project>"
    },
    {
        "path": "crysis-remastered-trainer/Program.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Threading;\nusing Memory;\n\nnamespace CrysisRemasteredTrainer\n{\n    /// <summary>\n    /// Main entry point for the Crysis Remastered Trainer.\n    /// </summary>\n    internal class Program\n    {\n        private static readonly Mem _memory = new Mem();\n        private const string ProcessName = \"CrysisRemastered\";\n\n        private static void Main(string[] args)\n        {\n            Console.Title = \"Crysis Remastered Trainer\";\n            Console.WriteLine(\"Waiting for Crysis Remastered...\");\n\n            // Wait for the game process to start\n            while (!_memory.OpenProcess(ProcessName))\n            {\n                Thread.Sleep(1000);\n            }\n\n            Console.WriteLine(\"Process found! Trainer ready.\");\n            Console.WriteLine(\"Hotkeys:\");\n            Console.WriteLine(\"  F1 - Toggle Unlimited Health\");\n            Console.WriteLine(\"  F2 - Toggle Unlimited Energy\");\n            Console.WriteLine(\"  F3 - Toggle Unlimited Ammo\");\n            Console.WriteLine(\"  F4 - Toggle Unlimited Suit Mode\");\n            Console.WriteLine(\"  F5 - Super Jump\");\n            Console.WriteLine(\"  F6 - Teleport to Waypoint\");\n\n            var healthToggle = false;\n            var energyToggle = false;\n            var ammoToggle = false;\n            var suitToggle = false;\n\n            // Addresses (example offsets, would need to be updated per game version)\n            var healthPtr = new IntPtr(0x017F2A90);\n            var energyPtr = new IntPtr(0x017F2A94);\n            var ammoPtr = new IntPtr(0x017F2A98);\n            var suitPtr = new IntPtr(0x017F2A9C);\n            var jumpOffset = 0x017F2AA0;\n\n            while (true)\n            {\n                if (Console.KeyAvailable)\n                {\n                    var key = Console.ReadKey(true).Key;\n                    switch (key)\n                    {\n                        case ConsoleKey.F1:\n                            healthToggle = !healthToggle;\n                            Console.WriteLine($\"Unlimited Health: {(healthToggle ? \"ON\" : \"OFF\")}\");\n                            break;\n                        case ConsoleKey.F2:\n                            energyToggle = !energyToggle;\n                            Console.WriteLine($\"Unlimited Energy: {(energyToggle ? \"ON\" : \"OFF\")}\");\n                            break;\n                        case ConsoleKey.F3:\n                            ammoToggle = !ammoToggle;\n                            Console.WriteLine($\"Unlimited Ammo: {(ammoToggle ? \"ON\" : \"OFF\")}\");\n                            break;\n                        case ConsoleKey.F4:\n                            suitToggle = !suitToggle;\n                            Console.WriteLine($\"Unlimited Suit Mode: {(suitToggle ? \"ON\" : \"OFF\")}\");\n                            break;\n                        case ConsoleKey.F5:\n                            // Super Jump: set Z velocity to a high value\n                            _memory.WriteMemory($\"0x{jumpOffset:X}\", \"float\", \"500.0\");\n                            Console.WriteLine(\"Super Jump activated!\");\n                            break;\n                        case ConsoleKey.F6:\n                            // Teleport: set position to a waypoint (example)\n                            _memory.WriteMemory(\"0x017F2AA4\", \"float\", \"1000.0\"); // X\n                            _memory.WriteMemory(\"0x017F2AA8\", \"float\", \"500.0\");  // Y\n                            _memory.WriteMemory(\"0x017F2AAC\", \"float\", \"200.0\");  // Z\n                            Console.WriteLine(\"Teleported to waypoint!\");\n                            break;\n                    }\n                }\n\n                // Apply toggles\n                if (healthToggle)\n                {\n                    _memory.WriteMemory($\"0x{healthPtr.ToInt64():X}\", \"int\", \"1000\");\n                }\n                if (energyToggle)\n                {\n                    _memory.WriteMemory($\"0x{energyPtr.ToInt64():X}\", \"int\", \"1000\");\n                }\n                if (ammoToggle)\n                {\n                    _memory.WriteMemory($\"0x{ammoPtr.ToInt64():X}\", \"int\", \"999\");\n                }\n                if (suitToggle)\n                {\n                    _memory.WriteMemory($\"0x{suitPtr.ToInt64():X}\", \"int\", \"1\");\n                }\n\n                Thread.Sleep(50); // Prevent CPU hogging\n            }\n        }\n    }\n}\n"
    },
