        "path": "crysis-remastered-trainer/MemoryManager.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace CrysisRemasteredTrainer\n{\n    /// <summary>\n    /// Provides low-level memory operations for the target process.\n    /// </summary>\n    public unsafe class MemoryManager : IDisposable\n    {\n        private IntPtr _processHandle;\n        private readonly int _processId;\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_VM_READ = 0x0010;\n        private const uint PROCESS_VM_WRITE = 0x0020;\n        private const uint PROCESS_VM_OPERATION = 0x0008;\n\n        /// <summary>\n        /// Initializes a new instance of <see cref=\"MemoryManager\"/>.\n        /// </summary>\n        /// <param name=\"processName\">The name of the target process.</param>\n        /// <exception cref=\"InvalidOperationException\">Thrown if the process is not found.</exception>\n        public MemoryManager(string processName)\n        {\n            var processes = Process.GetProcessesByName(processName);\n            if (processes.Length == 0)\n                throw new InvalidOperationException($\"Process '{processName}' not found.\");\n\n            _processId = processes[0].Id;\n            _processHandle = OpenProcess(PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION, false, _processId);\n\n            if (_processHandle == IntPtr.Zero)\n                throw new InvalidOperationException(\"Failed to open process handle.\");\n        }\n\n        /// <summary>\n        /// Reads a 32-bit integer from the specified address.\n        /// </summary>\n        public int ReadInt32(IntPtr address)\n        {\n            byte[] buffer = new byte[4];\n            if (!ReadProcessMemory(_processHandle, address, buffer, 4, out _))\n                throw new InvalidOperationException($\"Failed to read memory at {address.ToInt64():X}.\");\n            return BitConverter.ToInt32(buffer, 0);\n        }\n\n        /// <summary>\n        /// Writes a 32-bit integer to the specified address.\n        /// </summary>\n        public void WriteInt32(IntPtr address, int value)\n        {\n            byte[] buffer = BitConverter.GetBytes(value);\n            if (!WriteProcessMemory(_processHandle, address, buffer, 4, out _))\n                throw new InvalidOperationException($\"Failed to write memory at {address.ToInt64():X}.\");\n        }\n\n        /// <summary>\n        /// Writes a float value to the specified address.\n        /// </summary>\n        public void WriteFloat(IntPtr address, float value)\n        {\n            byte[] buffer = BitConverter.GetBytes(value);\n            if (!WriteProcessMemory(_processHandle, address, buffer, 4, out _))\n                throw new InvalidOperationException($\"Failed to write float at {address.ToInt64():X}.\");\n        }\n\n        /// <summary>\n        /// Reads a float value from the specified address.\n        /// </summary>\n        public float ReadFloat(IntPtr address)\n        {\n            byte[] buffer = new byte[4];\n            if (!ReadProcessMemory(_processHandle, address, buffer, 4, out _))\n                throw new InvalidOperationException($\"Failed to read float at {address.ToInt64():X}.\");\n            return BitConverter.ToSingle(buffer, 0);\n        }\n\n        /// <summary>\n        /// Releases the process handle.\n        /// </summary>\n        public void Dispose()\n        {\n            if (_processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n                _processHandle = IntPtr.Zero;\n            }\n        }\n    }\n}\n"
    },
