        "path": "crysis-remastered-trainer/CheatEngine.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing System.Threading;\n\nnamespace CrysisRemasteredTrainer\n{\n    /// <summary>\n    /// Manages cheat toggles and applies them to the game memory.\n    /// </summary>\n    public class CheatEngine : IDisposable\n    {\n        private readonly MemoryManager _memory;\n        private readonly Dictionary<string, bool> _toggles = new Dictionary<string, bool>();\n        private readonly Dictionary<string, IntPtr> _addresses;\n        private readonly Timer _applyTimer;\n\n        /// <summary>\n        /// Initializes a new instance of <see cref=\"CheatEngine\"/>.\n        /// </summary>\n        /// <param name=\"memory\">An active MemoryManager instance.</param>\n        /// <param name=\"addresses\">Dictionary mapping cheat names to memory addresses.</param>\n        public CheatEngine(MemoryManager memory, Dictionary<string, IntPtr> addresses)\n        {\n            _memory = memory ?? throw new ArgumentNullException(nameof(memory));\n            _addresses = addresses ?? throw new ArgumentNullException(nameof(addresses));\n\n            foreach (var key in addresses.Keys)\n            {\n                _toggles[key] = false;\n            }\n\n            // Apply cheat values every 100ms\n            _applyTimer = new Timer(ApplyCheats, null, 0, 100);\n        }\n\n        /// <summary>\n        /// Toggles a cheat by name.\n        /// </summary>\n        /// <param name=\"cheatName\">Name of the cheat (e.g., \"Health\").</param>\n        /// <returns>The new state (true = enabled).</returns>\n        public bool Toggle(string cheatName)\n        {\n            if (!_toggles.ContainsKey(cheatName))\n                throw new ArgumentException($\"Unknown cheat: {cheatName}\");\n\n            _toggles[cheatName] = !_toggles[cheatName];\n            return _toggles[cheatName];\n        }\n\n        /// <summary>\n        /// Gets the current state of a cheat.\n        /// </summary>\n        public bool IsEnabled(string cheatName)\n        {\n            return _toggles.TryGetValue(cheatName, out bool state) && state;\n        }\n\n        /// <summary>\n        /// Applies all enabled cheats to memory.\n        /// </summary>\n        private void ApplyCheats(object state)\n        {\n            foreach (var kvp in _toggles)\n            {\n                if (!kvp.Value) continue;\n\n                if (!_addresses.TryGetValue(kvp.Key, out IntPtr address)) continue;\n\n                try\n                {\n                    switch (kvp.Key)\n                    {\n                        case \"Health\":\n                            _memory.WriteInt32(address, 1000);\n                            break;\n                        case \"Energy\":\n                            _memory.WriteInt32(address, 1000);\n                            break;\n                        case \"Ammo\":\n                            _memory.WriteInt32(address, 999);\n                            break;\n                        case \"SuitMode\":\n                            _memory.WriteInt32(address, 1);\n                            break;\n                    }\n                }\n                catch (Exception ex)\n                {\n                    Console.Error.WriteLine($\"Failed to apply {kvp.Key}: {ex.Message}\");\n                }\n            }\n        }\n\n        /// <summary>\n        /// Performs a super jump by writing a high Y velocity.\n        /// </summary>\n        public void SuperJump(IntPtr velocityAddress)\n        {\n            _memory.WriteFloat(velocityAddress, 500.0f);\n        }\n\n        /// <summary>\n        /// Teleports the player to given coordinates.\n        /// </summary>\n        public void Teleport(float x, float y, float z, IntPtr basePosAddress)\n        {\n            _memory.WriteFloat(basePosAddress, x);\n            _memory.WriteFloat(basePosAddress + 4, y);\n            _memory.WriteFloat(basePosAddress + 8, z);\n        }\n\n        /// <summary>\n        /// Disposes the timer.\n        /// </summary>\n        public void Dispose()\n        {\n            _applyTimer?.Dispose();\n        }\n    }\n}\n"
    },
