        "path": "crysis-remastered-trainer/tests/TrainerTests.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing Xunit;\nusing Memory;\n\nnamespace CrysisRemasteredTrainer.Tests\n{\n    /// <summary>\n    /// Unit tests for the trainer logic (without actual memory access).\n    /// </summary>\n    public class TrainerTests\n    {\n        [Fact]\n        public void CheatEngine_Toggle_ChangesState()\n        {\n            // Arrange: Use a mock memory manager (not actually connecting to a process)\n            var mockMemory = new MockMemoryManager();\n            var addresses = new Dictionary<string, IntPtr>\n            {\n                { \"Health\", new IntPtr(0x1000) },\n                { \"Energy\", new IntPtr(0x1004) }\n            };\n            var engine = new CheatEngine(mockMemory, addresses);\n\n            // Act\n            var newState = engine.Toggle(\"Health\");\n\n            // Assert\n            Assert.True(newState);\n            Assert.True(engine.IsEnabled(\"Health\"));\n            Assert.False(engine.IsEnabled(\"Energy\"));\n        }\n\n        [Fact]\n        public void CheatEngine_Toggle_InvalidName_Throws()\n        {\n            var mockMemory = new MockMemoryManager();\n            var addresses = new Dictionary<string, IntPtr> { { \"Health\", new IntPtr(0x1000) } };\n            var engine = new CheatEngine(mockMemory, addresses);\n\n            Assert.Throws<ArgumentException>(() => engine.Toggle(\"Invalid\"));\n        }\n\n        [Fact]\n        public void CheatEngine_ApplyCheats_WritesCorrectValues()\n        {\n            var mockMemory = new MockMemoryManager();\n            var addresses = new Dictionary<string, IntPtr>\n            {\n                { \"Ammo\", new IntPtr(0x2000) }\n            };\n            var engine = new
